  z-index: 100;
  animation: dropdown-appear $transition-normal ease-out both;
}

.actions-dropdown__content {
  padding: $space-1;
  overflow-y: auto;
  max-height: 296px;

  &--slide-left {
    animation: submenu-slide-left $transition-normal ease-out both;
  }

  &--slide-right {
    animation: submenu-slide-right $transition-normal ease-out both;
  }
}

.actions-dropdown__back {
  display: flex;
  align-items: center;
  gap: $space-1;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: $text-600;
  font-family: $font-family;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  line-height: 1;
  text-align: left;
  margin-bottom: $space-1;
  transition: background-color $transition-fast ease;

  &:hover {
    background-color: $text-100;
  }

  svg {
    flex-shrink: 0;
  }
}

.actions-dropdown__item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: $space-4;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-sm;
  line-height: 1;
  text-align: left;
  transition: background-color $transition-fast ease;

  &:hover,
  &--active {
    background-color: $color-accent;
    color: $color-text-on-accent;

    .actions-dropdown__shortcut .kbd__key {
      background-color: $color-kbd-background-on-accent;
      color: $color-text-on-accent-secondary;
    }

    .actions-dropdown__chevron {
      color: $color-text-on-accent;
    }
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
    border-radius: $radius-md;
  }
}

.actions-dropdown__separator {
  height: 1px;
  margin: $space-1 $space-2;
  background-color: $border-100;
}

.actions-dropdown__section-title {
  padding: $space-1 + $space-half $space-3;
  font-family: $font-family;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  color: $text-400;
  line-height: 1;
  white-space: nowrap;
  user-select: none;
}

.actions-dropdown__label {
  white-space: nowrap;
}

.actions-dropdown__shortcut {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
}

.actions-dropdown__chevron {
  flex-shrink: 0;
  color: $text-400;
}

@keyframes dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(4px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes submenu-slide-left {
  from {
    opacity: 0;
    transform: translateX(8px);
  }

  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes submenu-slide-right {
  from {
    opacity: 0;
    transform: translateX(-8px);
  }

  to {
    opacity: 1;
    transform: translateX(0);
  }
}

