    setSubmenuDirection('exit');
    setSubmenu(null);
    setActiveIndex(0);
    return true;
  }, [submenu]);

  const executeAction = useCallback(
    (index: number) => {
      const action = flatActions[index];
      if (!action) return;
      if (action.submenu && action.submenu.length > 0) {
        openSubmenu(index);
        return;
      }
      action.onClick?.();
      onClose();
    },
    [flatActions, onClose, openSubmenu],
  );

  useEffect(() => {
    if (!open) return;

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === 'k' && e.metaKey) {
        e.preventDefault();
        e.stopPropagation();
        onClose();
        return;
      }

      if (e.key === 'Escape') {
        e.preventDefault();
        e.stopPropagation();
        if (!closeSubmenu()) {
          onClose();
        }
        return;
      }

      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        e.stopPropagation();
        closeSubmenu();
        return;
      }

      if (e.key === 'ArrowRight') {
        e.preventDefault();
        e.stopPropagation();
        openSubmenu(activeIndex);
        return;
      }

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        e.stopPropagation();
        setActiveIndex(i => (i < flatActions.length - 1 ? i + 1 : 0));
        return;
      }

